sys_script_include.script:
/**
 * @class RecordDeleter
 * @description Provides a functionality to delete records during the installation.
 * @since 24/02/2026
 * @date  24/02/2026
 * @version 1.0.0
 * @author Thomas Grensemann E-Mail: <thomas.grensemann@t-systems.com>
 *
 */
class RecordDeleter extends Record {


    /**
     * @description Deletes the record.
     *
     * @param {String} source source application
	 * @param {String} reason reason of the operation
     * @param {String} table The table to be used.
     * @param {String} sysId record sys_id
     * @param {Boolean} stealth modify data with setWorkflow() and autoSysFields()
     *
     * @returns {Boolean}  Flag that indicates whether the record was successfully deleted.
	 * 
	 * 			Valid values:

				true: Record was deleted.
				false: No record was found to delete.
     */
    recordDelete(source, reason, table, sysId, stealth) {
        stealth = stealth || false;
        let result = '';
		const query = QueryBuilder.findRecordBySysId(sysId);

        if (UtilityFunctions.isValidTable(table) && UtilityFunctions.isValidRecord(table, query)) {
            const params = {
                'table': table,
                'sysId': sysId,
                'stealth': UtilityFunctions.getBooleanValue(stealth),
                'result': ''

            };

            const script = ScriptBuider.getScriptRecordDelete();

            result = new ScriptEvaluator().executScript('global', script, params);

			this.processResult(result, source, 'Record delete', reason, table, {
				'sysId': sysId
			});

        } else {
            this.LOG_HANDLER.error(source, 'Record delete failed', reason, table, {
                'sysId': sysId
            });
        }

        return result;
    }
}
